<?php declare(strict_types=1); namespace App\Http\Controllers\Payroll; use App\Http\Controllers\Controller; use App\Http\Requests\Payroll\StoreEmployeeSalaryProfileRequest; use App\Models\Employee; use App\Models\Payroll\EmployeeSalaryProfile; use App\Models\Payroll\PayrollComponent; use Illuminate\Http\RedirectResponse; use Illuminate\Support\Facades\DB; use Illuminate\View\View; class EmployeeSalaryProfileController extends Controller{public function index():View{return view('payroll.profiles.index',['title'=>'Profil Gaji','profiles'=>EmployeeSalaryProfile::with('employee')->latest()->paginate(15)]);} public function create():View{return view('payroll.profiles.form',['title'=>'Tambah Profil Gaji','profile'=>new EmployeeSalaryProfile,'employees'=>Employee::where('is_active',true)->get(),'components'=>PayrollComponent::where('is_active',true)->get()]);} public function store(StoreEmployeeSalaryProfileRequest $r):RedirectResponse{DB::transaction(function()use($r){EmployeeSalaryProfile::where('employee_id',$r->employee_id)->where('is_active',true)->update(['is_active'=>false,'effective_end_date'=>now()->subDay()->toDateString()]);$p=EmployeeSalaryProfile::create($r->safe()->except('components')+['is_active'=>true,'created_by'=>$r->user()->id]);foreach($r->input('components',[]) as $c){$p->components()->create($c+['effective_start_date'=>$p->effective_start_date,'is_active'=>true]);}});return redirect()->route('payroll.salary-profiles.index')->with('status','Profil Gaji disimpan sebagai versi efektif baru.');} public function show(EmployeeSalaryProfile $salaryProfile):View{return view('payroll.profiles.show',['title'=>'Detail Profil Gaji','profile'=>$salaryProfile->load('employee','components.payrollComponent')]);} public function history(Employee $employee):View{return view('payroll.profiles.history',['title'=>'Histori Profil Gaji','employee'=>$employee,'profiles'=>EmployeeSalaryProfile::where('employee_id',$employee->id)->latest()->get()]);} public function missing():View{return view('payroll.profiles.missing',['title'=>'Pegawai Belum Memiliki Profil','employees'=>Employee::where('is_active',true)->whereDoesntHave('salaryProfiles')->paginate(15)]);}}
